// ============================================================
// Shared Types for GNSS System Frontend
// These types are used across pages and components.
// They are NOT generated by Orval — they extend backend types
// with frontend-specific fields (device status, telemetry, etc.)
// ============================================================

// ---------- Device types ----------
export type DeviceStatus = "online" | "offline" | "maintenance";

export interface UserDevice {
  id: string;
  name: string;
  speedLimitKmh: number;
  status: DeviceStatus;
  battery: number;
  lat: number;
  lng: number;
  cameraStatus: boolean;
  gnssStatus: boolean;
  lastSeen: string;
  createdAt: string;
}

export interface MqttCredentials {
  deviceId: string;
  mqttUsername: string;
  mqttPassword: string;
  mqttHost: string;
  mqttPort: number;
  mqttProtocol: string;
  topics: Record<string, string>;
}

export interface DeviceDetailInfo extends UserDevice {
  owner: string;
  satellites: number;
  hdop: number;
  vdop: number;
}

export interface SimpleDevice {
  id: string;
  name: string;
}

// ---------- Telemetry types ----------
export interface TelemetryPoint {
  lat: number;
  lng: number;
  speed: number;
  battery: number;
  timestamp: string;
}

// ---------- Alert types ----------
export type AlertType =
  | "speeding"
  | "geofence_exit"
  | "geofence_enter"
  | "signal_loss"
  | "signal_lost"
  | "dangerous_obstacle"
  | "trajectory_deviation"
  | "low_battery";

export interface UserAlert {
  id: string;
  deviceId: string;
  deviceName: string;
  type: AlertType;
  alertType?: string;
  message: string;
  isResolved: boolean;
  timestamp: string;
  createdAt?: string;
  device?: {
    id?: string;
    name?: string;
    [key: string]: unknown;
  };
  /** Optional media attachment */
  media?: {
    type: "image_frame" | "video_chunk";
    url: string;
    thumbnail: string;
    mediaLogId?: string;
  };
}

