// ---------- Geofence types ----------
export interface GeofenceZone {
  id: string;
  name: string;
  type: "allowed_zone" | "forbidden_zone";
  color: string;
  paths: { lat: number; lng: number }[];
  assignedDevices: string[];
  Devices?: unknown[];
  createdAt: string;
  vertexCount?: number;
}

// ---------- Dashboard types ----------
export interface DashboardDevice {
  id: string;
  name: string;
  status: "online" | "offline";
  lat: number;
  lng: number;
  battery: number;
  hdop: number;
  vdop: number;
  satellites: number;
  maxSatellites: number;
  lastSeen: string;
  type: "rover" | "base" | "relay";
}

export interface DashboardAlert {
  id: string;
  deviceId: string;
  deviceName: string;
  severity: "critical" | "warning" | "info";
  message: string;
  timestamp: string;
  acknowledged: boolean;
}

export interface DashboardMediaLog {
  id: string;
  deviceId: string;
  deviceName: string;
  thumbnail: string;
  objectDetected: string;
  confidence: number;
  timestamp: string;
  resolution: string;
}

export interface DashboardGeofence {
  id: string;
  name: string;
  color: string;
  paths: { lat: number; lng: number }[];
}

// ---------- Admin types ----------
export interface AdminDevice extends UserDevice {
  ownerId: string;
  ownerEmail: string;
}

export interface GlobalDevice {
  id: string;
  name: string;
  ownerEmail: string;
  ownerId: string;
  status: "online" | "offline" | "maintenance";
  lat: number;
  lng: number;
  battery: number;
  speed: number;
  lastSeen: string;
}

export interface AdminGeofence {
  id: string;
  name: string;
  ownerId: string;
  ownerEmail: string;
  pointCount: number;
  deviceCount: number;
  createdAt: string;
}

export interface AdminAlert {
  id: string;
  deviceId: string;
  deviceName: string;
  ownerId: string;
  ownerEmail: string;
  type: string;
  message: string;
  isResolved: boolean;
  hasMedia: boolean;
  timestamp: string;
}

export interface SystemUser {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  status: UserStatus;
  emailVerified: boolean;
  deviceCount: number;
  createdAt: string;
  lastLoginAt: string;
}

// ---------- Statistics types (Admin) ----------
export interface SystemOverview {
  totalUsers: number;
  activeUsers: number;
  totalDevices: number;
  onlineDevices: number;
  totalGeofences: number;
  totalAlerts: number;
}

export interface TelemetryStat {
  date: string;
  points: number;
}

export interface AlertTypeStat {
  name: string;
  count: number;
}

export interface MediaStat {
  date: string;
  images: number;
  videos: number;
}

export type UserRole = "admin" | "user";
export type UserStatus = "active" | "banned";
